transform_js:
var groups={};
rawData.rows.forEach(function(r){
  if(!groups[r.g]) groups[r.g]=[];
  groups[r.g].push(r.v);
});
var seriesData=[];
var cats=Object.keys(groups);
cats.forEach(function(g,gi){
  var sorted=groups[g].slice().sort(function(a,b){return a-b;});
  var counts={};
  sorted.forEach(function(v){
    counts[v]=(counts[v]||0)+1;
    var offset=(counts[v]-1)*0.15-(counts[v]-1)*0.075;
    seriesData.push([v, gi+offset]);
  });
});
transformedData={data:seriesData, cats:cats};
